import React, { useState, useEffect } from 'react';
import useAdmin from '../hooks/useAdmin';
import AdminSidebar from './components/AdminSidebar';
import { Navigate, Outlet } from 'react-router-dom';
import { Loader2, LogIn, ShieldAlert } from 'lucide-react';
import { motion } from 'framer-motion';

const AdminLayout = () => {
  const { isAdmin, loading } = useAdmin();
  const [showError, setShowError] = useState(false);

  useEffect(() => {
    if (!loading && !isAdmin) {
      setShowError(true);
    }
  }, [loading, isAdmin]);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gray-900 text-white gap-4">
        <motion.div 
          animate={{ rotate: 360 }}
          transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
        >
          <Loader2 className="h-10 w-10 text-blue-500" />
        </motion.div>
        <p className="text-gray-400 font-medium animate-pulse">Authenticating Admin Session...</p>
      </div>
    );
  }

  if (!isAdmin) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-6 text-center">
        <motion.div
           initial={{ scale: 0.9, opacity: 0 }}
           animate={{ scale: 1, opacity: 1 }}
           className="bg-white p-12 rounded-3xl shadow-2xl border border-gray-100 max-w-md w-full ring-1 ring-gray-900/5 group"
        >
          <div className="w-20 h-20 bg-red-100/50 rounded-2xl flex items-center justify-center mx-auto mb-6 text-red-600 transition-transform group-hover:scale-110">
            <ShieldAlert size={40} strokeWidth={2.5} />
          </div>
          <h2 className="text-3xl font-extrabold text-gray-900 mb-2">Access Denied</h2>
          <p className="text-gray-500 mb-8 leading-relaxed">
            This high-security portal is exclusive to StayEase staff. Your account does not have the necessary privileges.
          </p>
          <div className="space-y-3">
            <a 
              href="/login" 
              className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-blue-200 transition-all transform active:scale-95"
            >
              <LogIn size={20} />
              Switch to Staff Account
            </a>
            <a 
              href="/" 
              className="w-full flex items-center justify-center gap-2 bg-gray-50 hover:bg-gray-100 text-gray-600 font-bold py-4 rounded-2xl transition-all"
            >
              Back to Marketplace
            </a>
          </div>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex">
      {/* Sidebar - Fixed Width */}
      <AdminSidebar />

      {/* Main Content Area - Push right by sidebar width */}
      <main className="flex-1 ml-64 min-h-screen p-8">
        <div className="max-w-7xl mx-auto">
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;

import React, { useState, useEffect } from 'react';
import { 
  CalendarCheck, Calendar, User, 
  ChevronDown, CheckCircle2, XCircle, 
  Loader2, BadgeIndianRupee 
} from 'lucide-react';
import { adminService } from '../services/adminService';

const BookingManage = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchBookings = async () => {
    try {
      const data = await adminService.getBookings();
      setBookings(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBookings();
  }, []);

  const handleStatusChange = async (id, newStatus) => {
    try {
      await adminService.updateBookingStatus(id, newStatus);
      setBookings(bookings.map(b => b.id === id ? { ...b, status: newStatus } : b));
    } catch (err) {
      alert('Error updating status');
    }
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center min-h-[60vh]">
      <Loader2 className="h-10 w-10 text-blue-500 animate-spin" />
      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-4">Synchronizing Booking Ledger...</p>
    </div>
  );

  return (
    <div className="space-y-10 pb-20">
      <div>
        <h2 className="text-4xl font-extrabold text-gray-900 tracking-tight text-center md:text-left">Reservation Control</h2>
        <p className="text-gray-500 text-lg font-medium text-center md:text-left">Monitor and process global StayEase travel reservations.</p>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {bookings.map((b) => (
          <div key={b.id} className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-100 flex flex-col lg:flex-row lg:items-center justify-between gap-10 hover:shadow-xl transition-all border-l-8 border-l-blue-600">

             {/* Left: Metadata */}
             <div className="flex-1 flex flex-col md:flex-row items-center gap-8 text-center md:text-left">
                <div className="w-20 h-20 bg-blue-50 rounded-3xl flex items-center justify-center text-blue-600 shrink-0">
                   <CalendarCheck size={40} />
                </div>
                <div className="space-y-3">
                   <p className="text-xs text-gray-400 font-black uppercase tracking-widest">Reservation #{b.id.toString().padStart(6, '0')}</p>
                   <h3 className="text-2xl font-black text-gray-900 tracking-tight">{b.hotel_details?.name}</h3>
                   <div className="flex flex-wrap justify-center md:justify-start items-center gap-4 text-xs font-bold text-gray-500 uppercase tracking-wider">
                      <span className="flex items-center gap-1.5"><User size={14} className="text-blue-500" /> Guest: {b.user_details?.username} (#{b.user})</span>
                      <span className="flex items-center gap-1.5"><Calendar size={14} className="text-blue-500" /> {new Date(b.check_in).toLocaleDateString()} — {new Date(b.check_out).toLocaleDateString()}</span>
                   </div>
                </div>
             </div>

             {/* Right: Actions & Status */}
             <div className="flex items-center justify-center lg:justify-end gap-10 lg:pl-10 lg:border-l border-gray-100 min-w-80">
                <div className="text-center md:text-right space-y-2">
                   <p className="text-xs font-black uppercase tracking-widest text-gray-400">Total Settlement</p>
                   <div className="flex items-center justify-center md:justify-end gap-1 text-2xl font-black text-gray-900">
                      <BadgeIndianRupee size={24} className="text-blue-600" />
                      {b.total_price}
                   </div>
                </div>

                <div className="relative group">
                   <select 
                     value={b.status} 
                     onChange={(e) => handleStatusChange(b.id, e.target.value)}
                     className={`appearance-none font-black text-[10px] uppercase tracking-widest px-6 py-4 rounded-2xl cursor-pointer pr-12 transition-all outline-none border-2 ${
                       b.status === 'Confirmed' 
                       ? 'bg-green-100 text-green-700 border-green-200 hover:bg-green-200' 
                       : 'bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-200'
                     }`}
                   >
                     <option value="Pending">Pending Audit</option>
                     <option value="Confirmed">Mark Confirmed</option>
                     <option value="Cancelled">Cancel Reservation</option>
                   </select>
                   <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none opacity-50" size={16} />
                </div>
             </div>

          </div>
        ))}
        {bookings.length === 0 && (
           <div className="p-20 text-center space-y-6 bg-white rounded-[40px] border-2 border-dashed border-gray-200">
              <div className="w-24 h-24 bg-gray-50 mx-auto rounded-3xl flex items-center justify-center text-gray-200">
                 <CalendarCheck size={48} />
              </div>
              <p className="text-gray-400 font-black uppercase tracking-widest text-sm">No reservations found in database</p>
           </div>
        )}
      </div>
    </div>
  );
};

export default BookingManage;

import React, { useState, useEffect } from 'react';
import { Mail, Trash2, Calendar, Loader2, MessageSquare, Search, Filter } from 'lucide-react';
import { adminService } from '../services/adminService';

const ContactMessages = () => {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchMessages = async () => {
    try {
      const data = await adminService.getContacts();
      setMessages(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMessages();
  }, []);

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this message?')) {
      try {
        await adminService.deleteContact(id);
        setMessages(messages.filter(m => m.id !== id));
      } catch (err) {
        alert('Failed to delete message');
      }
    }
  };

  const filteredMessages = messages.filter(m => 
    m.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    m.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.message.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) return (
    <div className="flex flex-col items-center justify-center min-h-[60vh]">
      <Loader2 className="h-10 w-10 text-blue-500 animate-spin" />
      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-4">Retrieving Inquiries...</p>
    </div>
  );

  return (
    <div className="space-y-10 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-2">
        <div className="space-y-1">
          <h2 className="text-4xl font-extrabold text-gray-900 tracking-tight">Contact Messages</h2>
          <p className="text-gray-500 text-lg font-medium">Respond and manage community inquiries.</p>
        </div>
        <div className="relative w-full md:w-96 group">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-blue-600 transition-colors" size={20} />
          <input 
            type="text" 
            placeholder="Search by sender or content..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-14 pr-6 py-4 bg-white rounded-3xl border border-gray-100 shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium text-gray-900"
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {filteredMessages.map((m) => (
          <div key={m.id} className="bg-white rounded-[40px] p-10 shadow-sm border border-gray-100 flex flex-col justify-between hover:shadow-xl hover:border-blue-100 transition-all border-l-8 border-l-blue-600 group">
             <div className="space-y-6">
                <div className="flex items-start justify-between">
                   <div className="flex items-center gap-4">
                      <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 font-black tracking-widest uppercase">
                         {m.name[0]}
                      </div>
                      <div className="space-y-0.5">
                         <h4 className="text-xl font-black text-gray-900 tracking-tight uppercase leading-tight">{m.name}</h4>
                         <div className="flex items-center gap-2 text-xs font-bold text-gray-400">
                            <Mail size={12} className="text-blue-500" />
                            {m.email}
                         </div>
                      </div>
                   </div>
                   <button 
                     onClick={() => handleDelete(m.id)}
                     className="p-3 bg-red-50 text-red-500 rounded-2xl hover:bg-red-500 hover:text-white transition-all shadow-sm active:scale-95"
                   >
                     <Trash2 size={20} />
                   </button>
                </div>

                <div className="bg-gray-50 p-6 rounded-3xl relative">
                   <div className="absolute -top-2 left-6 px-3 bg-white border border-gray-100 rounded-lg text-[10px] uppercase font-black tracking-widest text-blue-600 shadow-sm">
                      Original Message
                   </div>
                   <p className="text-gray-600 leading-relaxed font-medium">
                      {m.message}
                   </p>
                </div>
             </div>

             <div className="mt-8 pt-8 border-t border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-2 text-xs font-black uppercase text-gray-400 tracking-widest">
                   <Calendar size={14} className="text-blue-500" />
                   {new Date(m.created_at).toLocaleString()}
                </div>
                <div className="flex items-center gap-1.5 py-1 px-3 bg-blue-50 rounded-full text-[10px] font-black uppercase tracking-widest text-blue-700 border border-blue-100">
                   <MessageSquare size={12} />
                   Awaiting Personnel
                </div>
             </div>
          </div>
        ))}

        {filteredMessages.length === 0 && (
           <div className="col-span-full p-32 text-center space-y-6 bg-white rounded-[60px] border-2 border-dashed border-gray-100">
              <div className="w-32 h-32 bg-gray-50 mx-auto rounded-full flex items-center justify-center text-gray-200">
                 <MessageSquare size={64} strokeWidth={1.5} />
              </div>
              <div className="space-y-2">
                 <p className="text-gray-900 font-black uppercase tracking-widest text-lg">Communication Silo Empty</p>
                 <p className="text-gray-400 font-bold tracking-tight">No active inquiries match your current parameters.</p>
              </div>
           </div>
        )}
      </div>
    </div>
  );
};

export default ContactMessages;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Users, Hotel, CalendarCheck, 
  MessageSquare, Banknote, 
  TrendingUp, ArrowRight, Loader2, AlertCircle, RefreshCcw 
} from 'lucide-react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { adminService } from '../services/adminService';

const StatCard = ({ title, value, icon: Icon, color, delay }) => (
  <motion.div
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0 }}
    transition={{ delay, duration: 0.5 }}
    className="bg-white p-7 rounded-3xl shadow-sm border border-gray-100 group hover:scale-[1.02] transition-all"
  >
    <div className="flex items-start justify-between">
      <div className="space-y-4 flex-1">
        <p className="text-sm font-bold text-gray-400 uppercase tracking-widest leading-none">{title}</p>
        <h3 className="text-4xl font-extrabold text-gray-900 leading-none">{value}</h3>
      </div>
      <div className={`p-4 rounded-2xl ${color} bg-opacity-10 ${color.replace('bg-', 'text-')}`}>
        <Icon size={30} strokeWidth={2.5} />
      </div>
    </div>
  </motion.div>
);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(null);

  const fetchStats = useCallback(async (isSilent = false) => {
    if (!isSilent) setLoading(true);
    else setRefreshing(true);

    try {
      const data = await adminService.getStats();
      setStats(data);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    fetchStats();
  }, [fetchStats]);

  if (loading) return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
      <Loader2 className="h-10 w-10 text-blue-500 animate-spin" />
      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Aggregating Statistics...</p>
    </div>
  );

  if (error) return (
    <div className="bg-red-50 border border-red-200 p-8 rounded-3xl text-center text-red-600 max-w-md mx-auto my-12 shadow-2xl">
      <AlertCircle className="mx-auto mb-4" size={48} />
      <h2 className="text-2xl font-extrabold mb-2">Analytics Error</h2>
      <p className="text-red-500 font-medium mb-6">{error}</p>
      <button onClick={() => fetchStats()} className="bg-red-600 text-white font-bold py-3 px-8 rounded-2xl">Retry</button>
    </div>
  );

  return (
    <div className="space-y-10 pb-20">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-4xl font-extrabold text-gray-900 tracking-tight">Dashboard Overview</h2>
          <p className="text-gray-500 text-lg font-medium">Welcome to the StayEase control center.</p>
        </div>
        <button 
          onClick={() => fetchStats(true)}
          className={`p-3 bg-white rounded-2xl shadow-sm border border-gray-100 ${refreshing ? 'animate-spin' : ''}`}
        >
          <RefreshCcw size={22} className="text-blue-600" />
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6">
        <StatCard title="Total Users" value={stats.total_users} icon={Users} color="bg-blue-600" delay={0.1} />
        <StatCard title="Bookings" value={stats.total_bookings} icon={CalendarCheck} color="bg-indigo-600" delay={0.2} />
        <StatCard title="Hotels" value={stats.total_hotels} icon={Hotel} color="bg-violet-600" delay={0.3} />
        <StatCard title="Reviews" value={stats.total_reviews} icon={MessageSquare} color="bg-pink-600" delay={0.4} />
        <StatCard title="Revenue" value={`₹${stats.revenue}`} icon={Banknote} color="bg-emerald-600" delay={0.5} />
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-8 flex items-center justify-between border-b border-gray-50">
           <h3 className="text-2xl font-extrabold text-gray-900">Recent Bookings</h3>
           <Link to="/admin/bookings" className="text-blue-600 font-extrabold flex items-center gap-2">
             View All <ArrowRight size={18} />
           </Link>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50/50">
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase">ID</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase">HOTEL</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase text-center">STATUS</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase text-right">DATE</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {stats.recent_activity.map((booking) => (
                <tr key={booking.id}>
                  <td className="px-8 py-5 text-sm font-bold text-gray-900">#{booking.id}</td>
                  <td className="px-8 py-5 text-sm font-bold text-gray-900">{booking.hotel_details?.name}</td>
                  <td className="px-8 py-5 text-center">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                      booking.status === 'Confirmed' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                    }`}>
                      {booking.status}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-sm text-gray-400 text-right">
                    {new Date(booking.created_at).toLocaleDateString()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Edit2, Trash2, MapPin, 
  Star, DollarSign, Loader2, X, Camera 
} from 'lucide-react';
import { adminService } from '../services/adminService';

const HotelManage = () => {
  const [hotels, setHotels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingHotel, setEditingHotel] = useState(null);
  const [formData, setFormData] = useState({
    name: '', location: '', price: '', 
    star_rating: '', description: '', available: true
  });
  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState(null);

  const fetchHotels = async () => {
    try {
      const data = await adminService.getHotels();
      setHotels(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHotels();
  }, []);

  const resetForm = () => {
    setFormData({ name: '', location: '', price: '', star_rating: '', description: '', available: true });
    setImageFile(null);
    setPreview(null);
    setEditingHotel(null);
    setIsModalOpen(false);
  };

  const openEditModal = (hotel) => {
    setEditingHotel(hotel);
    setFormData({
      name: hotel.name,
      location: hotel.location,
      price: hotel.price,
      star_rating: hotel.star_rating,
      description: hotel.description || '',
      available: hotel.available
    });
    setPreview(hotel.image ? (hotel.image.startsWith('http') ? hotel.image : `http://127.0.0.1:8000${hotel.image}`) : null);
    setIsModalOpen(true);
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImageFile(file);
      setPreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const data = new FormData();
    Object.keys(formData).forEach(key => data.append(key, formData[key]));
    if (imageFile) data.append('image', imageFile);

    try {
      await adminService.saveHotel(data, editingHotel?.id);
      fetchHotels();
      resetForm();
    } catch (err) {
      alert('Error saving hotel');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this hotel?')) {
      try {
        await adminService.deleteHotel(id);
        setHotels(hotels.filter(h => h.id !== id));
      } catch (err) {
        alert('Error deleting hotel');
      }
    }
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center min-h-[60vh]">
      <Loader2 className="h-10 w-10 text-blue-500 animate-spin" />
      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-4">Inventory Audit In Progress...</p>
    </div>
  );

  return (
    <div className="space-y-10 pb-20">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-4xl font-extrabold text-gray-900 tracking-tight">Hotel Management</h2>
          <p className="text-gray-500 text-lg font-medium">Control the StayEase luxury property portfolio.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg shadow-blue-200 uppercase tracking-widest text-xs transition-all active:scale-95"
        >
          <Plus size={18} /> Add New Property
        </button>
      </div>

      <div className="bg-white rounded-[32px] shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50/50">
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase">PROPERTY</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase text-center">RATE</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase text-center">RATING</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase text-center">AVAILABILITY</th>
                <th className="px-8 py-4 text-xs font-extrabold text-gray-400 uppercase text-right">ACTIONS</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {hotels.map((h) => (
                <tr key={h.id} className="hover:bg-gray-50 group transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-4">
                      <div className="w-16 h-12 bg-gray-100 rounded-xl overflow-hidden shadow-sm">
                        <img 
