import { useState, useEffect } from 'react';

const useAdmin = () => {
    const [isAdmin, setIsAdmin] = useState(false);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const checkAdmin = async () => {
            const token = localStorage.getItem('access_token');
            if (!token) {
                setIsAdmin(false);
                setLoading(false);
                return;
            }

            try {
                const response = await fetch('http://127.0.0.1:8000/api/auth/profile/', {
                    headers: { 'Authorization': `Bearer ${token}` }
                });

                if (response.ok) {
                    const data = await response.json();
                    // In your model, is_staff is the source of truth for admin panel access.
                    // However, we should also check the role if needed.
                    // Based on your requirements, only is_staff (admin users) can access.
                    // Django's AbstractUser has is_staff. We'll check it from the profile if it's returned.
                    // If your UserProfileSerializer does not include is_staff, we might need to add it or use 'role'.
                    // Let's assume for now role === 'manager' or we'll update the serializer.
                    // Actually, let's assume 'manager' or check if the backend allows the dashboard stats fetch.

                    const statsResp = await fetch('http://127.0.0.1:8000/api/admin/stats/', {
                        headers: { 'Authorization': `Bearer ${token}` }
                    });

                    if (statsResp.ok) {
                        setIsAdmin(true);
                    } else {
                        setIsAdmin(false);
                    }
                } else {
                    setIsAdmin(false);
                }
            } catch (err) {
                setError(err);
                setIsAdmin(false);
            } finally {
                setLoading(false);
            }
        };

        checkAdmin();
    }, []);

    return { isAdmin, loading, error };
};

export default useAdmin;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { CreditCard, Lock, CheckCircle, ShieldCheck, AlertCircle, Loader2 } from 'lucide-react';
import OTPModal from '../components/OTPModal';

const BookingPage = () => {
  const { hotelId } = useParams();
  const navigate = useNavigate();
  const [step, setStep] = useState('booking');
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', checkIn: '', checkOut: '' });
  const [paymentData, setPaymentData] = useState({ cardHolderName: '', cardNumber: '', expiryDate: '', cvv: '' });
  const [paymentErrors, setPaymentErrors] = useState({});
  const [isOTPModalOpen, setIsOTPModalOpen] = useState(false);
  const [otpError, setOtpError] = useState(null);
  const [otpLoading, setOtpLoading] = useState(false);

  useEffect(() => {
    if (!localStorage.getItem('access_token')) {
      alert("You must be logged in to make a booking.");
      navigate('/login');
    }
  }, [navigate]);

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });
  const handlePaymentChange = (e) => setPaymentData({ ...paymentData, [e.target.name]: e.target.value });

  const validatePayment = () => {
    const errors = {};
    if (!/^[A-Za-z\s]+$/.test(paymentData.cardHolderName)) errors.cardHolderName = "Alphabets only";
    if (!/^\d{16}$/.test(paymentData.cardNumber.replace(/\s/g, ''))) errors.cardNumber = "Exactly 16 digits";
    if (!/^(0[1-9]|1[0-2])\/(\d{2}|\d{4})$/.test(paymentData.expiryDate)) errors.expiryDate = "Format MM/YY";
    if (!/^\d{3,4}$/.test(paymentData.cvv)) errors.cvv = "3-4 digits";
    setPaymentErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleBookingSubmit = (e) => {
    e.preventDefault();
    setStep('payment');
  };

  const handlePaymentSubmit = async (e) => {
    if (e && e.preventDefault) e.preventDefault();
    if (!validatePayment()) return;

    setLoading(true);

    try {
      const response = await fetch('http://127.0.0.1:8000/api/bookings/send-payment-otp/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({ email: formData.email, purpose: 'payment' })
      });

      if (response.ok) {
        setIsOTPModalOpen(true);
      } else {
        const err = await response.json();
        alert(err.error || "Failed to send OTP.");
      }
    } catch (err) {
      alert("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyPayment = async (otpCode) => {
    setOtpLoading(true);
    setOtpError(null);

    try {
      // 1. Verify OTP first
      const otpResp = await fetch('http://127.0.0.1:8000/api/bookings/verify-payment-otp/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({ email: formData.email, otp_code: otpCode, purpose: 'payment' })
      });

      if (!otpResp.ok) {
        const err = await otpResp.json();
        throw new Error(err.error || "Invalid OTP code.");
      }

      // 2. Create Booking
      const bookingResp = await fetch('http://127.0.0.1:8000/api/bookings/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({
          hotel: hotelId,
          check_in: formData.checkIn,
          check_out: formData.checkOut,
          card_number: paymentData.cardNumber
        })
      });

      if (bookingResp.ok) {
        setIsOTPModalOpen(false);
        setStep('success');
      } else {
        const err = await bookingResp.json();
        throw new Error(err.error || "Failed to create booking.");
      }
    } catch (err) {
      setOtpError(err.message);
    } finally {
      setOtpLoading(false);
    }
  };

  const handleResendPaymentOTP = async () => {
    try {
      await fetch('http://127.0.0.1:8000/api/bookings/send-payment-otp/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({ email: formData.email, purpose: 'payment' })
      });
    } catch (err) {
      setOtpError("Failed to resend OTP.");
    }
  };


  return (
    <div className="pt-24 pb-16 min-h-screen bg-gray-50 flex flex-col justify-center">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 w-full">

        {/* Progress Bar */}
        <div className="mb-8 flex justify-center">
          <div className="flex items-center space-x-4">
            <div className={`flex items-center justify-center w-8 h-8 rounded-full font-bold text-white ${step === 'booking' || step === 'payment' || step === 'success' ? 'bg-blue-600' : 'bg-gray-300'}`}>1</div>
            <div className={`w-16 h-1 ${step === 'payment' || step === 'success' ? 'bg-blue-600' : 'bg-gray-300'}`}></div>
            <div className={`flex items-center justify-center w-8 h-8 rounded-full font-bold text-white ${step === 'payment' || step === 'success' ? 'bg-blue-600' : 'bg-gray-300'}`}>2</div>
            <div className={`w-16 h-1 ${step === 'success' ? 'bg-blue-600' : 'bg-gray-300'}`}></div>
            <div className={`flex items-center justify-center w-8 h-8 rounded-full font-bold text-white ${step === 'success' ? 'bg-blue-600' : 'bg-gray-300'}`}>3</div>
          </div>
        </div>

        <div className="bg-white shadow-xl rounded-2xl overflow-hidden border border-gray-100">

          {step === 'booking' && (
            <div className="px-8 py-10">
              <h2 className="text-3xl font-extrabold text-gray-900 text-center mb-8">
                Confirm Arrival Details
              </h2>
              <form onSubmit={handleBookingSubmit} className="space-y-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700">Full Name</label>
                  <input type="text" name="name" required className="mt-1 block w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border" value={formData.name} onChange={handleChange} />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700">Email Address</label>
                  <input type="email" name="email" required className="mt-1 block w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border" value={formData.email} onChange={handleChange} />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-medium text-gray-700">Check-in Date</label>
                    <input type="date" name="checkIn" required className="mt-1 block w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border cursor-pointer" value={formData.checkIn} onChange={handleChange} />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700">Check-out Date</label>
                    <input type="date" name="checkOut" required className="mt-1 block w-full border-gray-300 rounded-lg shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border cursor-pointer" value={formData.checkOut} onChange={handleChange} />
                  </div>
                </div>

                <div className="pt-6">
                  <button type="submit" className="w-full flex justify-center py-4 px-4 border border-transparent rounded-lg shadow-md text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-colors">
                    Proceed to Payment
                  </button>
                </div>
              </form>
            </div>
          )}

          {step === 'payment' && (
            <div className="px-8 py-10">
              <h2 className="text-3xl font-extrabold text-gray-900 text-center mb-4 flex items-center justify-center">
                <CreditCard className="mr-3 text-blue-600 w-8 h-8" /> Secure Payment
              </h2>
              <p className="text-center text-gray-500 mb-8 max-w-md mx-auto">Please enter your payment details below. Your transaction is securely encrypted and processed directly by our banking partner.</p>

              <form onSubmit={handlePaymentSubmit} className="space-y-6 max-w-lg mx-auto bg-gray-50 p-8 rounded-xl border border-gray-200">
                <div>
                  <label className="block text-sm font-bold text-gray-700">Cardholder Name</label>
                  <input 
                    type="text" 
                    name="cardHolderName" 
                    required 
                    placeholder="Ankit Tiwari" 
                    className={`mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border ${paymentErrors.cardHolderName ? 'border-red-500' : ''}`} 
                    value={paymentData.cardHolderName}
                    onChange={handlePaymentChange}
                  />
                  {paymentErrors.cardHolderName && <p className="text-red-500 text-xs mt-1">{paymentErrors.cardHolderName}</p>}
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700">Card Number</label>
                  <input 
                    type="text" 
                    name="cardNumber" 
                    required 
                    placeholder="0000 0000 0000 0000" 
                    maxLength="19" 
                    className={`mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border tracking-widest text-lg font-mono ${paymentErrors.cardNumber ? 'border-red-500' : ''}`} 
                    value={paymentData.cardNumber}
                    onChange={(e) => {
                      const value = e.target.value.replace(/\s/g, '').replace(/(\d{4})/g, '$1 ').trim();
                      setPaymentData({ ...paymentData, cardNumber: value });
                    }}
                  />
                  {paymentErrors.cardNumber && <p className="text-red-500 text-xs mt-1">{paymentErrors.cardNumber}</p>}
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-bold text-gray-700">Expiry Date</label>
                    <input 
                      type="text" 
                      name="expiryDate" 
                      required 
                      placeholder="MM/YY" 
                      maxLength="5" 
                      className={`mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border text-center ${paymentErrors.expiryDate ? 'border-red-500' : ''}`} 
                      value={paymentData.expiryDate}
                      onChange={(e) => {
                        let value = e.target.value.replace(/\D/g, '');
                        if (value.length > 2) value = value.substring(0,2) + '/' + value.substring(2);
                        setPaymentData({ ...paymentData, expiryDate: value });
                      }}
                    />
                    {paymentErrors.expiryDate && <p className="text-red-500 text-xs mt-1">{paymentErrors.expiryDate}</p>}
                  </div>
                  <div>
                    <label className="block text-sm font-bold text-gray-700">CVV</label>
                    <input 
                      type="password" 
                      name="cvv" 
                      required 
                      placeholder="123" 
                      maxLength="4" 
                      className={`mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm p-3 border text-center tracking-widest ${paymentErrors.cvv ? 'border-red-500' : ''}`} 
                      value={paymentData.cvv}
                      onChange={handlePaymentChange}
                    />
                    {paymentErrors.cvv && <p className="text-red-500 text-xs mt-1">{paymentErrors.cvv}</p>}
                  </div>
                </div>

                <div className="pt-6">
                  <button type="submit" disabled={loading} className="w-full flex items-center justify-center py-4 px-4 border border-transparent rounded-lg shadow-lg text-sm font-bold text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-colors disabled:opacity-50">
                    {loading ? 'Processing...' : <><Lock className="w-4 h-4 mr-2" /> Verify and Pay</>}
                  </button>
                </div>
              </form>
            </div>
          )}

          {step === 'success' && (
            <div className="px-8 py-16 text-center">
              <CheckCircle className="w-24 h-24 text-green-500 mx-auto mb-6" />
              <h2 className="text-4xl font-extrabold text-gray-900 mb-4">Payment Successful!</h2>
              <p className="text-xl text-gray-600 max-w-lg mx-auto mb-10">Your booking has been fully confirmed. We've instantly dispatched an email containing your hotel details and a complimentary welcome gift note!</p>
              <button onClick={() => navigate('/booking')} className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-full shadow-md transition-all">
                Return to Bookings
              </button>
            </div>
          )}

        <OTPModal
          isOpen={isOTPModalOpen}
          onClose={() => setIsOTPModalOpen(false)}
          email={formData.email}
          onVerify={handleVerifyPayment}
          onResend={handleResendPaymentOTP}
          loading={otpLoading}
          error={otpError}
        />
      </div>
    </div>
    </div>
  );
};

export default BookingPage;

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Eye, EyeOff, Check, X, ArrowRight, User, Mail, Lock, ShieldCheck, Loader2 } from 'lucide-react';
import OTPModal from '../components/OTPModal';

const Signup = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [isOTPModalOpen, setIsOTPModalOpen] = useState(false);
  const [otpError, setOtpError] = useState(null);
  const [otpLoading, setOtpLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const passwordMatch = formData.password === formData.confirmPassword && formData.password !== '';

  const hasMinLength = formData.password.length >= 8;
  const hasLetter = /[A-Za-z]/.test(formData.password);
  const hasDigit = /\d/.test(formData.password);
  const hasSpecialChar = /[^A-Za-z0-9]/.test(formData.password);

  const passwordValid = hasMinLength && hasLetter && hasDigit && hasSpecialChar;

  const handleSignup = async (e) => {
    e.preventDefault();
    if (!passwordValid || !passwordMatch) return;

    setError(null);
    setLoading(true);

    try {
      const response = await fetch('http://127.0.0.1:8000/api/auth/send-otp/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: formData.email, purpose: 'signup' })
      });

      const data = await response.json();
      if (!response.ok) {
         throw new Error(data.error || "Failed to send OTP. Please try again.");
      }
      setIsOTPModalOpen(true);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleVerifySignup = async (otpCode) => {
    setOtpLoading(true);
    setOtpError(null);

    const nameParts = formData.name.split(' ');
    const firstName = nameParts[0];
    const lastName = nameParts.slice(1).join(' ');

    try {
      const response = await fetch('http://127.0.0.1:8000/api/auth/verify-signup-otp/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          username: formData.email,
          email: formData.email,
          password: formData.password,
          first_name: firstName,
          last_name: lastName,
          otp_code: otpCode,
          purpose: 'signup'
        })
      });

      const data = await response.json();
      if (response.ok) {
        setIsOTPModalOpen(false);
        navigate('/login');
      } else {
        const errorMsg = data.error || (data.user_errors ? Object.values(data.user_errors).flat()[0] : "Invalid OTP code.");
        setOtpError(errorMsg);
      }
    } catch (err) {
      setOtpError("Failed to verify OTP. Please check your connection.");
    } finally {
      setOtpLoading(false);
    }
  };

  const handleResendOTP = async () => {
    setOtpError(null);
    try {
      await fetch('http://127.0.0.1:8000/api/auth/send-otp/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: formData.email, purpose: 'signup' })
      });
    } catch (err) {
      setOtpError("Failed to resend OTP.");
    }
  };

  const containerVariants = {
    hidden: { opacity: 0, x: -20 },
    visible: {
      opacity: 1,
      x: 0,
      transition: {
        duration: 0.6,
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 10 },
    visible: { opacity: 1, y: 0 }
  };

  return (
    <div className="min-h-screen bg-white flex">
      {/* Left Side: Form */}
      <div className="flex-1 flex flex-col justify-center py-12 px-4 sm:px-6 lg:flex-none lg:px-20 xl:px-24">
        <motion.div 
          initial="hidden"
          animate="visible"
          variants={containerVariants}
          className="mx-auto w-full max-w-sm lg:w-96"
        >
          <div>
            <motion.h2 variants={itemVariants} className="mt-6 text-3xl font-extrabold text-gray-900">
              Create your account
            </motion.h2>
            <motion.p variants={itemVariants} className="mt-2 text-sm text-gray-600">
              Join thousands of travelers finding their perfect stay.
            </motion.p>
          </div>

          <div className="mt-8">
            <div className="mt-6">
              <form onSubmit={handleSignup} className="space-y-6">
                <motion.div variants={itemVariants}>
                  <label htmlFor="name" className="block text-sm font-medium text-gray-700">
                    Full Name
                  </label>
                  <div className="mt-1 relative rounded-md shadow-sm">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                      <User className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                      id="name"
                      name="name"
                      type="text"
                      required
                      placeholder="Ankit Tiwari"
                      onChange={handleChange}
                      className="block w-full pl-10 sm:text-sm border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 p-3 border transition-all"
                    />
                  </div>
                </motion.div>

                <motion.div variants={itemVariants}>
                  <label htmlFor="email" className="block text-sm font-medium text-gray-700">
                    Email address
                  </label>
                  <div className="mt-1 relative rounded-md shadow-sm">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                      <Mail className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                      id="email"
                      name="email"
                      type="email"
                      required
                      placeholder="you@example.com"
                      onChange={handleChange}
                      className="block w-full pl-10 sm:text-sm border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 p-3 border transition-all"
                    />
                  </div>
                </motion.div>

                <motion.div variants={itemVariants}>
                  <label htmlFor="password" className="block text-sm font-medium text-gray-700">
                    Password
                  </label>
                  <div className="mt-1 relative rounded-md shadow-sm">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                      <Lock className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                      id="password"
                      name="password"
                      type={showPassword ? "text" : "password"}
                      required
                      placeholder="••••••••"
                      onChange={handleChange}
                      className="block w-full pl-10 pr-10 sm:text-sm border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 p-3 border transition-all"
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute inset-y-0 right-0 pr-3 flex items-center"
                    >
                      {showPassword ? <EyeOff className="h-5 w-5 text-gray-400" /> : <Eye className="h-5 w-5 text-gray-400" />}
                    </button>
                  </div>
                  {formData.password && (
                    <div className="mt-2 text-xs space-y-1">
                      <div className="flex items-center space-x-1">
                        {hasMinLength ? <Check className="h-4 w-4 text-green-500" /> : <X className="h-4 w-4 text-red-500" />}
                        <span className={hasMinLength ? 'text-green-600' : 'text-red-600'}>At least 8 characters</span>
                      </div>
                      <div className="flex items-center space-x-1">
                        {hasLetter && hasDigit ? <Check className="h-4 w-4 text-green-500" /> : <X className="h-4 w-4 text-red-500" />}
                        <span className={hasLetter && hasDigit ? 'text-green-600' : 'text-red-600'}>Alphanumeric (letters & numbers)</span>
                      </div>
                      <div className="flex items-center space-x-1">
                        {hasSpecialChar ? <Check className="h-4 w-4 text-green-500" /> : <X className="h-4 w-4 text-red-500" />}
                        <span className={hasSpecialChar ? 'text-green-600' : 'text-red-600'}>Special character (e.g., !@#$%)</span>
                      </div>
                    </div>
                  )}
                </motion.div>

                <motion.div variants={itemVariants}>
                  <label htmlFor="confirmPassword" className="block text-sm font-medium text-gray-700">
                    Confirm Password
                  </label>
                  <div className="mt-1 relative rounded-md shadow-sm">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                      <ShieldCheck className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                      id="confirmPassword"
                      name="confirmPassword"
                      type="password"
                      required
                      placeholder="••••••••"
                      onChange={handleChange}
                      className="block w-full pl-10 sm:text-sm border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 p-3 border transition-all"
                    />
                  </div>
                  <AnimatePresence>
                    {formData.confirmPassword && (
                      <motion.div 
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        className="mt-2 flex items-center space-x-1"
                      >
                        {passwordMatch ? <Check className="h-4 w-4 text-green-500" /> : <X className="h-4 w-4 text-red-500" />}
                        <span className={`text-xs ${passwordMatch ? 'text-green-600' : 'text-red-600'}`}>
                          {passwordMatch ? "Passwords match" : "Passwords do not match"}
                        </span>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.div>

                <AnimatePresence>
                  {error && (
                    <motion.div 
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      className="bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded-lg text-sm"
                    >
                      {error}
                    </motion.div>
                  )}
                </AnimatePresence>

                <motion.div variants={itemVariants}>
                  <button
                    type="submit"
                    disabled={loading || !passwordValid || !passwordMatch}
                    className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-all disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95"
                  >
                    {loading ? (
                      <svg className="animate-spin h-5 w-5 mr-3 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                    ) : (
                      <>
                        Sign up & Verify Email
                        <ArrowRight className="ml-2 h-4 w-4" />
                      </>
                    )}
                  </button>
                </motion.div>
              </form>
            </div>

            <motion.div variants={itemVariants} className="mt-6 text-center text-sm text-gray-600">
              Already have an account?{' '}
              <Link to="/login" className="font-bold text-blue-600 hover:text-blue-500 transition-colors">
                Log in
              </Link>
            </motion.div>
          </div>
        </motion.div>
      </div>

      {/* Right Side: Image/Branding */}
      <div className="hidden lg:block relative flex-1 w-0">
        <img
          className="absolute inset-0 h-full w-full object-cover"
          src="https://images.unsplash.com/photo-1469474968028-56623f02e42e?q=80&w=2074&auto=format&fit=crop"
          alt="Travel Nature"
        />
        <div className="absolute inset-0 bg-blue-600 mix-blend-multiply opacity-20"></div>
        <div className="absolute inset-0 flex flex-col justify-center px-20 text-white">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4, duration: 0.8 }}
          >
            <h1 className="text-5xl font-extrabold tracking-tight">
              Start your journey <br /> with <span className="text-blue-500">StayEase</span>.
            </h1>
            <p className="mt-6 text-xl max-w-lg">
              Unlock exclusive deals and discover hidden gems across the globe. Your next adventure starts here.
            </p>
          </motion.div>
        </div>
      </div>

      <OTPModal
        isOpen={isOTPModalOpen}
        onClose={() => setIsOTPModalOpen(false)}
        email={formData.email}
        onVerify={handleVerifySignup}
        onResend={handleResendOTP}
        loading={otpLoading}
        error={otpError}
      />
    </div>
  );
};

export default Signup;
